            # Base Case
            if a is None and b is None:
                return True
            if (a is None and b is not None) or (a is not None and b is None):
                return False
            if a.val != b.val:
                return False

            # Recursion
            # pre
            # recur
            left = is_same(a.left, b.left)
            right = is_same(a.right, b.right)
            # post
            both_same = left &amp; right

            # return
            return both_same

        return is_same(p, q)

