from typing import Self

class PTNode:
    char: str
    children: dict[str, Self]
    terminal: bool

    def __init__(self, char: str) -&gt; None:
        if len(char) &gt; 1:
            msg = &quot;Must instantiate PT with char not str&quot;
            raise ValueError(msg)

        self.char = char
        self.children = {}
        self.terminal = False

    def add(self, char: str) -&gt; Self | None:
        if len(char) &gt; 1:
            msg = f&quot;Must instantiate PT with char not str: {char}&quot;
            raise ValueError(msg)

        if char in self.children:
            return self.children[char]

        newnode = PTNode(char)
        self.children[char] = newnode
        return newnode

    def get(self, char: str) -&gt; Self | None:
        if len(char) &gt; 1:
            msg = &quot;Must instantiate PT with char not str&quot;
            raise ValueError(msg)

        if char in self.children:
            return self.children[char]

        return None


class Trie:
    dummyhead: PTNode

    def __init__(self):
        self.dummyhead = PTNode(char=&quot;&quot;)

    def insert(self, word: str) -&gt; None:
        cur = self.dummyhead
        for char in word:
            cur = cur.add(char)

        cur.terminal = True

    def search(self, word: str) -&gt; bool:
        cur = self.dummyhead
        for char in word:
            cur = cur.get(char)
            if cur is None:
                return False

        return cur.terminal

    def startsWith(self, prefix: str) -&gt; bool:
        cur = self.dummyhead
        for char in prefix:
            cur = cur.get(char)
            if cur is None:
                return False
        return True


