Quicksort.content:
Definition:
A Sorting Algorithm which takes advantage of Divide and Conquer to sort a list.

Notes:


Get a pivot value p.
Any element which is less than the pivot is moved to the left front.

This divides the array into (values less than p)-(p)-(values greater than p)


Pick new pivots for the values in the left and right of the first pivot.

This now divides values into (&lt;p_1)-p_1-(p_1 \le x\le p_0)-(p_0)-…






















[\lep_0\le]LOWp_1p_2HIGH


























87645 (pivot)4 (swap)768 (swap)545 (pivotswap)687 (pivotswap)

Runtime: Big O of O(n \log n), memory of O(1) per partition pass since we do it in place, but due to Recursion stack it is O(\log n) extra memory.

// Pick pivot. Move all smol values to before the pivot.
function partition(arr: number[], lo: number, hi: number); number {
	const pivot = arr[hi]; // hi is pivot

	let idx = lo-1; // tracks start of low section
	// scan through low-to-pivot for smol values
	for (let i = lo; i &lt; hi; ++i) {
		if (arr[i] &lt;= pivot) {
			idx++;
			const tmp = arr[i];
			arr[i] = arr[idx];
			arr[idx] = tmp;  // swap so smol value goes to lo
		}
	}

	// swap so pivot goes to pivotspot
	idx++;
	arr[hi] = arr[idx];
	arr[idx] = pivot;

	return idx;
}

// Do the recusive quicksort
function qs(arr: number[], lo: number, hi: number); void {
	// base case
	if (lo &gt;= hi) {
		return;
	}

	const pivot_idx = partition(arr, lo, hi);
	// sort the left half
	qs(arr, lo, pivot_idx-1);  // don&#039;t include the pivot!
	// sort the right half
	qs(arr, pivot_idx+1, hi); 
}

// The runner
export default function quick_sort(arr: number[]); void {
	qs(arr, 0, arr.length - 1);  // both low and HIGH(!) are inclusive
}

